/* TriplePrmtMgmtMapper.getTriplePrmtDupByInfo */ SELECT DISTINCT A.PRMT_ID AS prmtId , B.RATE_CD AS rateCd FROM MSP_TRIPLE_PRMT A , MSP_TRIPLE_PRMT_RATE B WHERE A.USG_YN = 'Y' AND A.PRMT_ID = B.PRMT_ID AND #{strtDt} <= A.END_DT AND #{endDt} >= A.STRT_DT
AND B.RATE_CD IN (SELECT SOC.RATE_CD FROM MSP_TRIPLE_PRMT_RATE SOC WHERE SOC.PRMT_ID = #{prmtId}) AND A.PRMT_ID NOT IN (#{prmtId})
ORDER BY B.RATE_CD

mapper.insert:

SELECT 'T' || TO_CHAR(SYSDATE, 'YYYYMMDD') || TRIM(TO_CHAR(TO_NUMBER(NVL(SUBSTR(MAX(PRMT_ID),10), '000')) + 1, '000')) AS prmtId
FROM   MSP_TRIPLE_PRMT
WHERE  SUBSTR(PRMT_ID, 2, 8) = TO_CHAR(SYSDATE, 'YYYYMMDD')

/* TriplePrmtMgmtMapper.insertMspTriplePrmt */
INSERT INTO MSP_TRIPLE_PRMT (
	 PRMT_ID
	,PRMT_NM
	,STRT_DT
	,END_DT
	,USG_YN
	,REGST_ID
	,REGST_DTTM
	,RVISN_ID
	,RVISN_DTTM
) VALUES (
	 #{prmtId}
	,#{prmtNm}
	,#{strtDt}
	,#{endDt}
	,NVL(#{usgYn}, 'Y')
	,#{sessionUserId}
	,SYSDATE
	,#{sessionUserId}
	,SYSDATE
)

mapper.update:
/* TriplePrmtMgmtMapper.updTriplePrmtByInfo */
UPDATE  MSP_TRIPLE_PRMT
SET     RVISN_ID = #{sessionUserId}
		,RVISN_DTTM = SYSDATE



					,USG_YN = NVL(#{usgYn}, 'N')


					,END_DT = #{endDt}



WHERE  PRMT_ID = #{prmtId}

