/* TriplePrmtMgmtMapper.getExcelUpSocList */ SELECT DECODE(B.RATE_CD, NULL, '0', '1') AS rowCheck ,A.RATE_CD AS rateCd ,A.RATE_NM AS rateNm ,A.DATA_TYPE AS dataType ,A.BASE_AMT AS baseAmt FROM MSP_RATE_MST A ,(SELECT RATE_CD FROM MSP_RATE_MST WHERE 1=1
AND RATE_CD IN
#{item}
) B WHERE A.RATE_CD = B.RATE_CD(+) AND A.APPL_END_DT = '99991231' AND A.SERVICE_TYPE = 'P' AND A.PAY_CL_CD = 'PO' ORDER BY rowCheck DESC, dataType DESC, rateNm
